from dataclasses import dataclass, field

@dataclass
class PlanState:
    """Tracks which plan steps are done and which remain."""
    all_steps: list[str]
    completed: list[str] = field(default_factory=list)
    revised_remaining: list[str] | None = None  # set when replanning occurs

    @property
    def remaining(self) -> list[str]:
        if self.revised_remaining is not None:
            return self.revised_remaining
        done = set(self.completed)
        return [s for s in self.all_steps if s not in done]

    def mark_done(self, step: str):
        self.completed.append(step)
        if self.revised_remaining and step in self.revised_remaining:
            self.revised_remaining.remove(step)

    def replan(self, new_remaining: list[str]):
        """Replace remaining steps without touching completed steps."""
        self.revised_remaining = new_remaining

    def summary(self) -> str:
        return (
            f"Completed: {self.completed}\n"
            f"Remaining: {self.remaining}"
        )

# Example usage:
state = PlanState(all_steps=["search F1", "check F1 availability", "book cheapest"])
state.mark_done("search F1")
state.mark_done("check F1 availability")
# Observation: F1 sold out — replan the remaining step
state.replan(["search F2", "check F2 availability", "book F2"])
print(state.summary())
# Completed: ['search F1', 'check F1 availability']
# Remaining: ['search F2', 'check F2 availability', 'book F2']

import anthropic
import json

client = anthropic.Anthropic()

REPLANNING_INJECTION = (
    "Your last {n} actions did not make progress. "
    "Stop repeating the same approach. "
    "Choose a completely different tool or query strategy. "
    "If no alternative exists, call task_failed."
)

WRAP_UP_INJECTION = (
    "The context is growing large. Synthesise what you know so far "
    "into the best answer you can and call task_complete now. "
    "Do not make more tool calls."
)

class ReplanningController:
    """
    Detects stalled progress and injects replanning messages.
    """
    def __init__(
        self,
        consecutive_error_threshold: int = 3,
        repeat_call_threshold: int = 2,
        context_warn_fraction: float = 0.70,
        context_limit: int = 200_000,
    ):
        self.consecutive_error_threshold = consecutive_error_threshold
        self.repeat_call_threshold = repeat_call_threshold
        self.context_warn_fraction = context_warn_fraction
        self.context_limit = context_limit

        self._consecutive_errors = 0
        self._last_calls: list[tuple[str, str]] = []  # (tool, args_hash)

    def record_observation(self, is_error: bool):
        if is_error:
            self._consecutive_errors += 1
        else:
            self._consecutive_errors = 0

    def record_call(self, tool: str, args: dict):
        import hashlib
        key = (tool, hashlib.md5(json.dumps(args, sort_keys=True).encode()).hexdigest()[:8])
        self._last_calls.append(key)
        if len(self._last_calls) > self.repeat_call_threshold + 2:
            self._last_calls = self._last_calls[-(self.repeat_call_threshold + 2):]

    def needs_replanning(self) -> str | None:
        """Returns an injection message if replanning is needed, else None."""
        if self._consecutive_errors >= self.consecutive_error_threshold:
            return REPLANNING_INJECTION.format(n=self._consecutive_errors)
        if (len(self._last_calls) >= self.repeat_call_threshold and
                len(set(self._last_calls[-self.repeat_call_threshold:])) == 1):
            return REPLANNING_INJECTION.format(n=self.repeat_call_threshold)
        return None

    def needs_wrap_up(self, current_input_tokens: int) -> bool:
        return current_input_tokens >= self.context_limit * self.context_warn_fraction

def run_with_replanning_controller(system, tools, dispatch, user_message, max_iterations=15):
    controller = ReplanningController()
    messages = [{"role": "user", "content": user_message}]

    for iteration in range(1, max_iterations + 1):
        resp = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=512,
            system=system,
            tools=tools,
            messages=messages,
        )
        messages.append({"role": "assistant", "content": resp.content})
        tool_calls = [b for b in resp.content if b.type == "tool_use"]

        # Check for control tools
        for block in tool_calls:
            if block.name in ("task_complete", "task_failed"):
                return {"status": block.name, "result": block.input, "iterations": iteration}

        if not tool_calls:
            return {"status": "stuck", "iterations": iteration}

        results = []
        for block in tool_calls:
            controller.record_call(block.name, block.input)
            fn = dispatch.get(block.name)
            result = fn(**block.input) if fn else json.dumps({"error": f"Unknown: {block.name}"})
            results.append({"type": "tool_result", "tool_use_id": block.id, "content": result})
            is_error = '"ok": false' in result or '"error"' in result
            controller.record_observation(is_error)

        # Check context size
        if controller.needs_wrap_up(resp.usage.input_tokens):
            results.append({"type": "text", "text": WRAP_UP_INJECTION})

        messages.append({"role": "user", "content": results})

        # Check if replanning injection is needed (insert before next model call)
        replan_msg = controller.needs_replanning()
        if replan_msg:
            messages.append({"role": "user", "content": replan_msg})

    return {"status": "max_iterations", "iterations": max_iterations}
